package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Page;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP08FiltrarPedidosEstadoMesPlaywrightTest extends BaseTestPlaywright {    @Test    void administradorFiltraPedidosPorEstadoYMes() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']").fill("admin");        page.locator("input[name='password']").fill("admin");        page.locator("button[type='submit']").click();        page.waitForTimeout(2000);        assertTrue(                page.content().contains("Panel Administrador"),                "No se visualiza el Panel Administrador."        );        page.locator("select[name='status']")                .selectOption("delivered");        page.locator("select[name='month']")                .selectOption("6");        page.locator("button.filter-submit")                .click();        page.waitForTimeout(2000);        assertTrue(                page.content().contains("Estadísticas")                        || page.content().contains("Total Pedidos Completados")                        || page.content().contains("Total Ganancias"),                "No se muestran las estadísticas después del filtro."        );        assertTrue(                page.content().contains("delivered"),                "No se muestran pedidos con estado delivered."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get(                                "evidencias/HP08-filtro-estado-mes.png"))                        .setFullPage(true)        );    }}